// src/pages/OrderConfirmation.jsx
import React, { useEffect, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../styles/style.css';

export default function OrderConfirmation() {
  const location = useLocation();
  const navigate = useNavigate();
  const [order, setOrder] = useState(location.state || null);
  const [previousOrders, setPreviousOrders] = useState([]);

  useEffect(() => {
    if (!order) return;

    const phone = order.phoneNumber;
    const url = process.env.REACT_APP_API_URL
      ? `${process.env.REACT_APP_API_URL}/api/orders?phone=${phone}`
      : `http://localhost:5000/api/orders?phone=${phone}`;

    axios.get(url)
      .then(res => {
        const previous = res.data
          .filter(o => o.orderId !== order.orderId)
          .map(o => ({ ...o, total: parseFloat(o.total) }));
        setPreviousOrders(previous);
      })
      .catch(err => console.error('Failed to fetch previous orders', err));
  }, [order]);

  if (!order) return <p>Waiting for your order...</p>;

  const items = order.items || [];
  const total = items.reduce((sum, it) => sum + it.price * it.qty, 0);

  const handlePrint = () => window.print();

  return (
    <div
      className="invoice-container"
      style={{
        background: 'url("/images/wood-background.jpg") center/cover no-repeat',
        minHeight: '100vh',
        padding: '50px 20px',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'flex-start'
      }}
    >
      <div
        className="invoice-card"
        style={{
          background: 'rgba(34, 28, 18, 0.95)',
          backdropFilter: 'blur(8px)',
          color: '#f5e1c0',
          boxShadow: '0 15px 40px rgba(0,0,0,0.6)',
          borderRadius: '20px',
          padding: '40px 30px',
          maxWidth: '800px',
          width: '100%'
        }}
      >
        {/* Navigation */}
        <button
          className="back-home-btn"
          style={{ backgroundColor: '#8b5e3c', color: '#fff', marginBottom: '20px' }}
          onClick={() => navigate('/home')}
        >
          ← Back to Home
        </button>

        {/* Header */}
        <h1 style={{ color: '#f0c27b', textAlign: 'center', marginBottom: '5px' }}>Thank You for Your Order!</h1>
        <p className="invoice-subtitle" style={{ textAlign: 'center', color: '#f5e1c0', marginBottom: '25px' }}>Mostafa Restaurant</p>

        {/* Print Button */}
        <button
          className="print-btn"
          style={{
            background: 'linear-gradient(135deg, #b88658, #8b5e3c)',
            color: '#fff',
            marginBottom: '30px'
          }}
          onClick={handlePrint}
        >
          🖨️ Print Invoice
        </button>

        {/* Customer Info */}
        <section className="invoice-section">
          <h2 style={{ color: '#f0c27b' }}>Customer Information</h2>
          <p><strong>Name:</strong> {order.fullName}</p>
          <p><strong>Phone:</strong> {order.phoneNumber}</p>
          {order.notes && <p><strong>Notes:</strong> {order.notes}</p>}
        </section>

        {/* Order Details */}
        <section className="invoice-section">
          <h2 style={{ color: '#f0c27b' }}>Order Details</h2>
          <table className="invoice-table" style={{ marginBottom: '15px' }}>
            <thead>
              <tr>
                <th>Item</th>
                <th>Qty</th>
                <th>Price ($)</th>
                <th>Subtotal ($)</th>
              </tr>
            </thead>
            <tbody>
              {items.map((it, idx) => (
                <tr key={idx}>
                  <td>{it.item_name}</td>
                  <td>{it.qty}</td>
                  <td className="price-cell">${parseFloat(it.price).toFixed(2)}</td>
                  <td className="subtotal-cell">${(it.price * it.qty).toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
          </table>
          <p className="invoice-total pulse" style={{ textAlign: 'right', marginTop: '10px' }}>Total: ${total.toFixed(2)}</p>
        </section>

        {/* Previous Orders */}
        <section className="invoice-section">
          <h2 style={{ color: '#f0c27b' }}>Previous Orders</h2>
          {previousOrders.length > 0 ? (
            <ul>
              {previousOrders.map((o, i) => (
                <li key={i}>
                  <strong>{o.fullName || o.customer_name}</strong>: Total ${o.total.toFixed(2)}
                </li>
              ))}
            </ul>
          ) : <p>No previous orders.</p>}
        </section>

        {/* Footer */}
        <p className="invoice-footer" style={{ textAlign: 'center', marginTop: '30px', color: '#f5e1c0' }}>
          We appreciate your business! Enjoy your meal 🍽️
        </p>
      </div>
    </div>
  );
}
